import product1 from "./assets/iphone.webp";
import product2 from "./assets/samsung.png";
import product3 from "./assets/pixel.png";
import product4 from "./assets/oneplus.png";
import product5 from "./assets/xiaomi.png";

export const PRODUCTS = [
    { id: 1, name: "Apple iPhone 14 Pro Max", price: 999.00, productImg: product1 },
    { id: 2, name: "Samsung Galaxy S23",      price: 899.00, productImg: product2 },
    { id: 3, name: "Google Pixel 7",          price: 799.00, productImg: product3 },
    { id: 4, name: "OnePlus 11",              price: 699.00, productImg: product4 },
    { id: 5, name: "Xiaomi 13",               price: 599.00, productImg: product5 },
];
